// 1. استخراج النص الخام من رد Groq
// Accessing the nested path safely
const choice = items[0].json.choices && items[0].json.choices[0];
const rawContent = choice ? choice.message.content : "{}";

// 2. تنظيف النص من أي زيادات (Markdown, Code Blocks)
// Removes ```json, ```, and extra whitespace
let cleanContent = rawContent
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// 3. محاولة تحويل النص لـ JSON
try {
  // Parse the clean string
  const parsedData = JSON.parse(cleanContent);

  // 4. تجهيز كائن البيانات النهائي (لضمان وجود كل الحقول)
  // We explicitly map fields to ensure they exist (defaulting to null if missing)
  const finalOutput = {
    is_receipt: parsedData.is_receipt || false,
    status: parsedData.status || null,
    total_amount: parsedData.total_amount || parsedData.total || null, // Handle variations
    currency: parsedData.currency || "EGP",
    date: parsedData.date || null,
    time: parsedData.time || null,
    reference_number: parsedData.reference_number || parsedData.transaction_id || null,
    sender: parsedData.sender_name || null,
    receiver: parsedData.receiver_name || null,
    receiver_phone: parsedData.receiver_phone || null,
    bank: parsedData.bank_name || parsedData.merchant || null,
    category: parsedData.category || null,

    // بنحتفظ بالرد الأصلي عشان لو حبيت تراجعه
    _raw_response: rawContent
  };

  return [{ json: finalOutput }];

} catch (error) {
  // في حالة الفشل، رجع رسالة خطأ مع النص الأصلي عشان تعرف السبب
  return [{ 
    json: { 
      error: "Failed to parse JSON", 
      message: error.message,
      raw_input: cleanContent 
    } 
  }];
}
